import "./navbar.css";
import { Link } from "react-router-dom";

function Navbar() {

    return (
        <nav className="container-navbar">
            <ul className="nav-list">
                <Link to="index.html"><img src="LOGO-B.png" alt='Logo' /></Link>
                <li className="nav-item"><Link to="/">INICIO</Link></li>

                <li className="nav-item-menuv">
                    <Link to="/Productos">PRODUCTOS</Link>
                </li>
                <li className="nav-item"><Link to="Contacto">CONTACTO</Link></li>
                <li className="nav-item-carrito"><Link to="/Carrito"><img src="carrito.svg" className="carrito-img-navbar" alt="Carrito"/></Link><span className="cant-en-carrito">10</span></li>
            </ul>
        </nav>

    );
};

export default Navbar;
